  1	import * as React from 'react';
  2	import {
  3	  Chart,
  4	  ChartProps,
  5	  ChartVoronoiContainer,
  6	  ChartAxis,
  7	  ChartScatter,
  8	  ChartArea,
  9	  ChartLabel,
 10	  ChartLegend,
 11	  ChartThreshold
 12	} from '@patternfly/react-charts';
 13	
 14	import { VCLines, VCDataPoint, RichDataPoint } from 'types/VictoryChartInfo';
 15	import { CustomTooltip } from './CustomTooltip';
 16	import { VCEvent, addLegendEvent } from 'utils/VictoryEvents';
 17	import { PFColors } from 'components/Pf/PfColors';
 18	
 19	type Props = ChartProps & {
 20	  labelName: string;
 21	  name: string;
 22	  series: VCLines<RichDataPoint>;
 23	  showLegend?: boolean;
 24	  showXAxisValues?: boolean;
 25	  showYAxis?: boolean;
 26	  tooltipFormat?: (dp: VCDataPoint) => string;
 27	  thresholds?: VCLines<RichDataPoint>;
 28	};
 29	
 30	type State = {
 31	  width: number;
 32	  hiddenSeries: Set<number>;
 33	};
 34	
 35	const axisStyle = {
 36	  tickLabels: { fill: PFColors.Color100 }
 37	};
 38	
 39	export const INTERPOLATION_STRATEGY = 'monotoneX';
 40	
 41	export class SparklineChart extends React.Component<Props, State> {
 42	  containerRef?: React.RefObject<HTMLDivElement>;
 43	
 44	  constructor(props: Props) {
 45	    super(props);
 46	    if (props.width === undefined) {
 47	      this.containerRef = React.createRef<HTMLDivElement>();
 48	    }
 49	    this.state = { width: props.width || 1, hiddenSeries: new Set() };
 50	  }
 51	
 52	  private handleResize = () => {
 53	    if (this.containerRef && this.containerRef.current) {
 54	      this.setState({ width: this.containerRef.current.clientWidth });
 55	    }
 56	  };
 57	
 58	  componentDidMount() {
 59	    if (this.containerRef) {
 60	      setTimeout(() => {
 61	        this.handleResize();
 62	        window.addEventListener('resize', this.handleResize);
 63	      });
 64	    }
 65	  }
 66	
 67	  componentWillUnmount() {
 68	    if (this.containerRef) {
 69	      window.removeEventListener('resize', this.handleResize);
 70	    }
 71	  }
 72	
 73	  render() {
 74	    if (this.containerRef) {
 75	      return <div ref={this.containerRef}>{this.renderChart()}</div>;
 76	    }
 77	    return this.renderChart();
 78	  }
 79	
 80	  private renderChart() {
 81	    const legendHeight = 30;
 82	    let height = this.props.height || 300;
 83	    let padding = { top: 0, bottom: 0, left: 0, right: 0 };
 84	    if (this.props.padding) {
 85	      const p = this.props.padding as number;
 86	      if (Number.isFinite(p)) {
 87	        padding = { top: p, bottom: p, left: p, right: p };
 88	      } else {
 89	        padding = { ...padding, ...(this.props.padding as object) };
 90	      }
 91	    }
 92	    const events: VCEvent[] = [];
 93	    if (this.props.showLegend) {
 94	      padding.bottom += legendHeight;
 95	      height += legendHeight;
 96	      this.props.series.forEach((_, idx) => {
 97	        addLegendEvent(events, {
 98	          legendName: this.props.name + '-legend',
 99	          idx: idx,
100	          serieID: [this.props.name + '-area-' + idx],
101	          onClick: () => {
102	            if (!this.state.hiddenSeries.delete(idx)) {
103	              // Was not already hidden => add to set
104	              this.state.hiddenSeries.add(idx);
105	            }
106	            this.setState({ hiddenSeries: new Set(this.state.hiddenSeries) });
107	            return null;
108	          },
109	          onMouseOver: props => {
110	            return {
111	              style: { ...props.style, strokeWidth: 4, fillOpacity: 0.5 }
112	            };
113	          }
114	        });
115	      });
116	    }
117	
118	    const container = (
119	      <ChartVoronoiContainer
120	        labels={obj => (this.props.tooltipFormat ? this.props.tooltipFormat(obj.datum) : obj.datum.y)}
121	        labelComponent={<CustomTooltip />}
122	        voronoiBlacklist={this.props.series.map((_, idx) => this.props.name + '-scatter-' + idx)}
123	      />
124	    );
125	    const hiddenAxisStyle = {
126	      axis: { stroke: 'none' },
127	      ticks: { stroke: 'none' },
128	      tickLabels: { stroke: 'none', fill: 'none' }
129	    };
130	
131	    return (
132	      <Chart
133	        {...this.props}
134	        height={height}
135	        width={this.state.width}
136	        padding={padding}
137	        events={events as any[]}
138	        containerComponent={container}
139	        // Hack: 1 pxl on Y domain padding to prevent harsh clipping (https://github.com/kiali/kiali/issues/2069)
140	        domainPadding={{ y: 1 }}
141	      >
142	        {this.props.showXAxisValues ? (
143	          <ChartAxis
144	            tickValues={this.props.series[0].datapoints.map(dp => dp.x)}
145	            tickFormat={x => (x as Date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
146	            tickCount={2}
147	            style={axisStyle}
148	          />
149	        ) : (
150	          <ChartAxis tickCount={15} style={hiddenAxisStyle} />
151	        )}
152	        {this.props.showYAxis ? (
153	          <ChartAxis
154	            label={this.props.labelName}
155	            axisLabelComponent={
156	              <ChartLabel y={-5} x={15} angle={0} renderInPortal={true} style={{ fill: PFColors.Color100 }} />
157	            }
158	            tickCount={2}
159	            dependentAxis={true}
160	            style={axisStyle}
161	          />
162	        ) : (
163	          <ChartAxis dependentAxis={true} style={hiddenAxisStyle} />
164	        )}
165	        {this.props.series.map((serie, idx) => {
166	          if (this.state.hiddenSeries.has(idx)) {
167	            return undefined;
168	          }
169	          return (
170	            <ChartScatter
171	              name={this.props.name + '-scatter-' + idx}
172	              key={this.props.name + '-scatter-' + idx}
173	              data={serie.datapoints}
174	              style={{ data: { fill: serie.color } }}
175	              size={({ active }) => (active ? 5 : 2)}
176	            />
177	          );
178	        })}
179	        {this.props.series.map((serie, idx) => {
180	          if (this.state.hiddenSeries.has(idx)) {
181	            return undefined;
182	          }
183	          return (
184	            <ChartArea
185	              name={this.props.name + '-area-' + idx}
186	              key={this.props.name + '-area-' + idx}
187	              data={serie.datapoints}
188	              style={{
189	                data: {
190	                  fill: serie.color,
191	                  fillOpacity: 0.2,
192	                  stroke: serie.color,
193	                  strokeWidth: 2
194	                }
195	              }}
196	              interpolation={INTERPOLATION_STRATEGY}
197	            />
198	          );
199	        })}
200	        {this.props.showLegend && (
201	          <ChartLegend
202	            name={this.props.name + '-legend'}
203	            data={this.props.series.map((s, idx) => {
204	              if (this.state.hiddenSeries.has(idx)) {
205	                return { ...s.legendItem, symbol: { fill: PFColors.Color200 } };
206	              }
207	              return s.legendItem;
208	            })}
209	            y={height - legendHeight}
210	            height={legendHeight}
211	            width={this.state.width}
212	          />
213	        )}
214	
215	        {this.props.thresholds &&
216	          this.props.thresholds.map((serie, idx) => {
217	            if (this.state.hiddenSeries.has(idx)) {
218	              return undefined;
219	            }
220	            return (
221	              <ChartThreshold
222	                data={serie.datapoints}
223	                style={{
224	                  data: { stroke: serie.color }
225	                }}
226	              />
227	            );
228	          })}
229	      </Chart>
230	    );
231	  }
232	}

